solution.code:
#include <stdio.h>
#include <stdbool.h>

int main() {
    int n = 1;
    bool is_prime = (n > 1);
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            is_prime = false;
            break;
        }
    }
    if (is_prime) printf("Prime\n");
    else printf("Not Prime\n");
    return 0;
}
